//! Integration tests for icons functionality

use fastmcp_server::{Server, ServerBuilder};
use fastmcp_protocol::types::*;

#[tokio::test]
async fn test_tools_list_includes_icons() {
    let server = ServerBuilder::new("test", "1.0")
        .tool(tool_with_icon("search", "search-icon.png"))
        .tool(tool_without_icon("compute"))
        .build();

    let result = server.list_tools().await.unwrap();

    let search = result.tools.iter().find(|t| t.name == "search").unwrap();
    assert!(search.icon.is_some());
    assert_eq!(search.icon.as_ref().unwrap().src.as_deref(), Some("search-icon.png"));

    let compute = result.tools.iter().find(|t| t.name == "compute").unwrap();
    assert!(compute.icon.is_none());
}

